const oldCost = parseFloat($('Change Request Data').item.json.old_value) || 0;
const newCost = parseFloat($('Change Request Data').item.json.new_value) || 0;
const bomData = $('Fetch BOM').item.json.data;

// Count how many times PRT-101 appears in BOM
const targetPart = $('Change Request Data').item.json.part_number;
const lines = bomData.split('\n');
let totalQty = 0;

lines.forEach(line => {
  if (line.includes(targetPart)) {
    const cols = line.split(',');
    const qty = parseInt(cols[4]) || 0;
    totalQty += qty;
  }
});

const unitDelta = newCost - oldCost;
const annualVolume = totalQty * 52;
const annualImpact = unitDelta * annualVolume;

return [{
  json: {
    old_unit_cost: oldCost.toFixed(2),
    new_unit_cost: newCost.toFixed(2),
    unit_cost_delta: unitDelta.toFixed(2),
    total_qty_in_bom: totalQty,
    annual_volume: annualVolume,
    annual_cost_impact: annualImpact.toFixed(2),
    impact_direction: annualImpact > 0 ? 'INCREASE' : 'DECREASE'
  }
}];

